import com.fasterxml.jackson.databind.ObjectMapper;

public class SecureDeserializationExample {

    public static void main(String[] args) {
        String serializedObject = "{\"name\":\"John\",\"age\":30}";

        ObjectMapper objectMapper = new ObjectMapper();

        try {
            Person person = objectMapper.readValue(serializedObject, Person.class);
            System.out.println("Deserialized object: " + person.getName() + ", " + person.getAge());
        } catch (Exception e) {
            System.err.println("Error during deserialization: " + e.getMessage());
        }
    }

    static class Person {
        private String name;
        private int age;

        public String getName() {
            return name;
        }

        public void setName(String name) {
            this.name = name;
        }

        public int getAge() {
            return age;
        }

        public void setAge(int age) {
            this.age = age;
        }
    }
}

